  ('aboriginal-b0f95c3f-moex-00055', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '依憲法及相關司法院大法官解釋，有關軍事與國防，下列敘述何者正確？', '["總統統率全國陸海空軍，全國陸海空軍須效忠總統，保護人民", "國防與軍事事項，由中央立法，地方執行之", "軍事審判機關所行使者，亦屬國家刑罰權之一種，具有司法權之性質", "現役與退役軍人，均不得兼任文官"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
